// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// List AMT devices
	// (GET /api/v1/amt/devices)
	ListAMTDevices(ctx context.Context, request ListAMTDevicesRequestObject) (ListAMTDevicesResponseObject, error)
	// Get AMT device details
	// (GET /api/v1/amt/devices/{uuid})
	GetAMTDevice(ctx context.Context, request GetAMTDeviceRequestObject) (GetAMTDeviceResponseObject, error)
	// Send power command to AMT device
	// (POST /api/v1/amt/devices/{uuid}/power)
	AmtPowerAction(ctx context.Context, request AmtPowerActionRequestObject) (AmtPowerActionResponseObject, error)
	// Query audit log (admin only)
	// (GET /api/v1/audit)
	ListAuditEvents(ctx context.Context, request ListAuditEventsRequestObject) (ListAuditEventsResponseObject, error)
	// Authenticate user
	// (POST /api/v1/auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Register a new user
	// (POST /api/v1/auth/register)
	Register(ctx context.Context, request RegisterRequestObject) (RegisterResponseObject, error)
	// Report a browser-side error for server-side log ingestion
	// (POST /api/v1/client-errors)
	ReportClientError(ctx context.Context, request ReportClientErrorRequestObject) (ReportClientErrorResponseObject, error)
	// List devices, optionally filtered by group
	// (GET /api/v1/devices)
	ListDevices(ctx context.Context, request ListDevicesRequestObject) (ListDevicesResponseObject, error)
	// Delete device
	// (DELETE /api/v1/devices/{id})
	DeleteDevice(ctx context.Context, request DeleteDeviceRequestObject) (DeleteDeviceResponseObject, error)
	// Get device details
	// (GET /api/v1/devices/{id})
	GetDevice(ctx context.Context, request GetDeviceRequestObject) (GetDeviceResponseObject, error)
	// Update device fields
	// (PATCH /api/v1/devices/{id})
	UpdateDevice(ctx context.Context, request UpdateDeviceRequestObject) (UpdateDeviceResponseObject, error)
	// Rank anomalous metric dimensions for a device window
	// (POST /api/v1/devices/{id}/correlate)
	CorrelateDevice(ctx context.Context, request CorrelateDeviceRequestObject) (CorrelateDeviceResponseObject, error)
	// Get hardware info for a device
	// (GET /api/v1/devices/{id}/hardware)
	GetDeviceHardware(ctx context.Context, request GetDeviceHardwareRequestObject) (GetDeviceHardwareResponseObject, error)
	// On-demand full-resolution local history for one dimension
	// (GET /api/v1/devices/{id}/history)
	GetDeviceHistory(ctx context.Context, request GetDeviceHistoryRequestObject) (GetDeviceHistoryResponseObject, error)
	// Discovered software and service inventory for a device
	// (GET /api/v1/devices/{id}/inventory)
	GetDeviceInventory(ctx context.Context, request GetDeviceInventoryRequestObject) (GetDeviceInventoryResponseObject, error)
	// Broker an on-demand raw-log pull from a device
	// (GET /api/v1/devices/{id}/logs)
	GetDeviceLogs(ctx context.Context, request GetDeviceLogsRequestObject) (GetDeviceLogsResponseObject, error)
	// Downsampled numeric telemetry for a device window
	// (GET /api/v1/devices/{id}/metrics)
	GetDeviceMetrics(ctx context.Context, request GetDeviceMetricsRequestObject) (GetDeviceMetricsResponseObject, error)
	// Restart agent on device
	// (POST /api/v1/devices/{id}/restart)
	RestartDevice(ctx context.Context, request RestartDeviceRequestObject) (RestartDeviceResponseObject, error)
	// Enroll agent using token (public)
	// (POST /api/v1/enroll/{token})
	Enroll(ctx context.Context, request EnrollRequestObject) (EnrollResponseObject, error)
	// List enrollment tokens (admin only)
	// (GET /api/v1/enrollment-tokens)
	ListEnrollmentTokens(ctx context.Context, request ListEnrollmentTokensRequestObject) (ListEnrollmentTokensResponseObject, error)
	// Create enrollment token (admin only)
	// (POST /api/v1/enrollment-tokens)
	CreateEnrollmentToken(ctx context.Context, request CreateEnrollmentTokenRequestObject) (CreateEnrollmentTokenResponseObject, error)
	// Delete enrollment token (admin only)
	// (DELETE /api/v1/enrollment-tokens/{id})
	DeleteEnrollmentToken(ctx context.Context, request DeleteEnrollmentTokenRequestObject) (DeleteEnrollmentTokenResponseObject, error)
	// List user's groups
	// (GET /api/v1/groups)
	ListGroups(ctx context.Context, request ListGroupsRequestObject) (ListGroupsResponseObject, error)
	// Create a device group
	// (POST /api/v1/groups)
	CreateGroup(ctx context.Context, request CreateGroupRequestObject) (CreateGroupResponseObject, error)
	// Delete group
	// (DELETE /api/v1/groups/{id})
	DeleteGroup(ctx context.Context, request DeleteGroupRequestObject) (DeleteGroupResponseObject, error)
	// Get group details
	// (GET /api/v1/groups/{id})
	GetGroup(ctx context.Context, request GetGroupRequestObject) (GetGroupResponseObject, error)
	// Health check
	// (GET /api/v1/health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Purge all telemetry for an organization (admin only)
	// (POST /api/v1/orgs/{orgId}/purge)
	PurgeOrg(ctx context.Context, request PurgeOrgRequestObject) (PurgeOrgResponseObject, error)
	// Get purge job status
	// (GET /api/v1/purge-jobs/{jobId})
	GetPurgeJob(ctx context.Context, request GetPurgeJobRequestObject) (GetPurgeJobResponseObject, error)
	// Remove push subscription
	// (DELETE /api/v1/push/subscribe)
	UnsubscribePush(ctx context.Context, request UnsubscribePushRequestObject) (UnsubscribePushResponseObject, error)
	// Save browser push subscription
	// (POST /api/v1/push/subscribe)
	SubscribePush(ctx context.Context, request SubscribePushRequestObject) (SubscribePushResponseObject, error)
	// Get server VAPID public key
	// (GET /api/v1/push/vapid-key)
	GetVapidKey(ctx context.Context, request GetVapidKeyRequestObject) (GetVapidKeyResponseObject, error)
	// List all security groups (admin only)
	// (GET /api/v1/security-groups)
	ListSecurityGroups(ctx context.Context, request ListSecurityGroupsRequestObject) (ListSecurityGroupsResponseObject, error)
	// Create a security group (admin only)
	// (POST /api/v1/security-groups)
	CreateSecurityGroup(ctx context.Context, request CreateSecurityGroupRequestObject) (CreateSecurityGroupResponseObject, error)
	// Delete a security group (admin only)
	// (DELETE /api/v1/security-groups/{id})
	DeleteSecurityGroup(ctx context.Context, request DeleteSecurityGroupRequestObject) (DeleteSecurityGroupResponseObject, error)
	// Get security group with members (admin only)
	// (GET /api/v1/security-groups/{id})
	GetSecurityGroup(ctx context.Context, request GetSecurityGroupRequestObject) (GetSecurityGroupResponseObject, error)
	// Add user to security group (admin only)
	// (POST /api/v1/security-groups/{id}/members)
	AddSecurityGroupMember(ctx context.Context, request AddSecurityGroupMemberRequestObject) (AddSecurityGroupMemberResponseObject, error)
	// Remove user from security group (admin only)
	// (DELETE /api/v1/security-groups/{id}/members/{userId})
	RemoveSecurityGroupMember(ctx context.Context, request RemoveSecurityGroupMemberRequestObject) (RemoveSecurityGroupMemberResponseObject, error)
	// Get server CA certificate PEM
	// (GET /api/v1/server/ca)
	GetServerCA(ctx context.Context, request GetServerCARequestObject) (GetServerCAResponseObject, error)
	// Get agent install script
	// (GET /api/v1/server/install.sh)
	GetInstallScript(ctx context.Context, request GetInstallScriptRequestObject) (GetInstallScriptResponseObject, error)
	// List active sessions for a device
	// (GET /api/v1/sessions)
	ListSessions(ctx context.Context, request ListSessionsRequestObject) (ListSessionsResponseObject, error)
	// Create a relay session
	// (POST /api/v1/sessions)
	CreateSession(ctx context.Context, request CreateSessionRequestObject) (CreateSessionResponseObject, error)
	// Delete a relay session
	// (DELETE /api/v1/sessions/{token})
	DeleteSession(ctx context.Context, request DeleteSessionRequestObject) (DeleteSessionResponseObject, error)
	// List all agent update manifests
	// (GET /api/v1/updates/manifests)
	ListUpdateManifests(ctx context.Context, request ListUpdateManifestsRequestObject) (ListUpdateManifestsResponseObject, error)
	// Publish a new agent binary version (admin only)
	// (POST /api/v1/updates/manifests)
	PublishUpdate(ctx context.Context, request PublishUpdateRequestObject) (PublishUpdateResponseObject, error)
	// Push update to connected agents (admin only)
	// (POST /api/v1/updates/push)
	PushUpdate(ctx context.Context, request PushUpdateRequestObject) (PushUpdateResponseObject, error)
	// Get the Ed25519 public signing key
	// (GET /api/v1/updates/signing-key)
	GetUpdateSigningKey(ctx context.Context, request GetUpdateSigningKeyRequestObject) (GetUpdateSigningKeyResponseObject, error)
	// Get per-device update status for a version (admin only)
	// (GET /api/v1/updates/status/{version})
	GetUpdateStatus(ctx context.Context, request GetUpdateStatusRequestObject) (GetUpdateStatusResponseObject, error)
	// List all users (admin only)
	// (GET /api/v1/users)
	ListUsers(ctx context.Context, request ListUsersRequestObject) (ListUsersResponseObject, error)
	// Get current user
	// (GET /api/v1/users/me)
	GetMe(ctx context.Context, request GetMeRequestObject) (GetMeResponseObject, error)
	// Delete user (admin only)
	// (DELETE /api/v1/users/{id})
	DeleteUser(ctx context.Context, request DeleteUserRequestObject) (DeleteUserResponseObject, error)
	// Update user (admin only)
	// (PATCH /api/v1/users/{id})
	UpdateUser(ctx context.Context, request UpdateUserRequestObject) (UpdateUserResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

